{
  "essential_purpose": "ローカル環境で完結するTODO管理REST APIを提供し、外部ネットワークに依存せずタスクの作成・参照・更新・削除を安全に行えるようにする",
  "background": "外部サービスに依存しないローカル完結型のTODO管理が必要。データはSQLiteで永続化し、認証付きREST APIとして提供する。ネットワーク接続がない環境でも動作することが前提条件",
  "goals": [
    {"id": "G1", "text": "ローカル専用のTODO REST APIをセキュアに提供する"},
    {"id": "G2", "text": "SQLiteによるデータ永続化で信頼性のあるTODO管理を実現する"},
    {"id": "G3", "text": "外部ネットワーク通信なしで完全にオフライン動作する"}
  ],
  "objectives": [
    {"id": "O1", "text": "TODO CRUDの全操作がREST APIで実行可能", "measure": "POST/GET/PUT/DELETE の4操作が正常動作"},
    {"id": "O2", "text": "JWT認証でAPIアクセスを保護", "measure": "認証なしリクエストが401で拒否される"},
    {"id": "O3", "text": "SQLiteでデータが永続化される", "measure": "サーバ再起動後もデータが保持される"}
  ],
  "success_criteria": [
    "全CRUD操作がREST APIで実行可能",
    "JWT認証が正常に動作する",
    "SQLiteにデータが永続化される",
    "外部ネットワーク通信が一切発生しない"
  ],
  "stakeholders": [
    {"status": "not_applicable", "reason": "ローカル専用個人ツールのため外部ステークホルダーなし。利用者は開発者本人のみ"}
  ],
  "scope": {
    "in": [
      "TODO項目のCRUD REST API",
      "JWT認証・認可",
      "SQLiteによるデータ永続化",
      "ローカルホストでのAPI提供"
    ],
    "out": [
      "外部ネットワーク通信",
      "クラウドデプロイ",
      "フロントエンドUI",
      "マルチユーザー同時アクセス制御"
    ]
  },
  "constraints": [
    "外部ネットワーク通信を一切行わない",
    "データベースはSQLiteのみ使用",
    "ローカルマシン上でのみ動作"
  ],
  "concrete_intents": [
    {"id": "I1", "text": "TODO項目を作成・取得・更新・削除するREST APIエンドポイントを実装する", "serves": ["G1"]},
    {"id": "I2", "text": "JWT認証でAPIへのアクセスを制御する", "serves": ["G1"]},
    {"id": "I3", "text": "SQLiteファイルにTODOデータを永続化する", "serves": ["G2"]},
    {"id": "I4", "text": "外部DNS/HTTPリクエストを一切発生させない設計にする", "serves": ["G3"]}
  ],
  "confirmed": true,
  "approval_ref": "appr-foundation-001"
}

